// POKEMON HUB SAYFASI
function pokemonPage(pslug){
  const cardSlugs = POKEMON_CARDS[pslug];
  if(!cardSlugs) return null;
  const pname = POKEMON_NAMES[pslug] || pslug;
  const title = esc(pname + ' Pokemon Kartları — Tüm Versiyonlar & Fiyatları | Kartist');
  // En pahalı kart
  const topCard = CARDS[cardSlugs[0]];
  const maxPrice = topCard ? topCard[2] : 0;
  const desc = esc(pname + ' Pokemon kartlarının tam listesi (' + cardSlugs.length + ' kart). Tüm setlerdeki ' + pname + ' versiyonları, güncel Türkiye fiyatları ve değerleri. En değerli: $' + maxPrice.toFixed(0) + ' — Kartist.');
  const canonical = SITE + '/pokemon/' + pslug;

  const tiles = cardSlugs.map(cardTile).join('');
  const schema = {"@context":"https://schema.org","@type":"CollectionPage","name":pname+' Pokemon Kartları',"description":desc.slice(0,200),"url":canonical};
  const pcrumbs = {"@context":"https://schema.org","@type":"BreadcrumbList","itemListElement":[
    {"@type":"ListItem","position":1,"name":"Ana Sayfa","item":SITE+"/"},
    {"@type":"ListItem","position":2,"name":pname+" Kartları","item":canonical}]};

  return `<!DOCTYPE html><html lang="tr"><head>
<meta charset="UTF-8"><meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>${title}</title><meta name="description" content="${desc}">
<link rel="canonical" href="${canonical}"><meta name="robots" content="index, follow">
<meta property="og:type" content="website"><meta property="og:title" content="${title}">
<meta property="og:description" content="${desc}"><meta property="og:url" content="${canonical}">
<meta property="og:image" content="${SITE}/og-image.png"><meta property="og:locale" content="tr_TR">
<meta name="twitter:card" content="summary_large_image">
<script type="application/ld+json">${JSON.stringify(schema)}</script>
<script type="application/ld+json">${JSON.stringify(pcrumbs)}</script>
<link rel="icon" type="image/png" href="${SITE}/og-image.png">${HEAD_FONTS}${HEAD_CSS}</head><body>
<div class="bg-glow"></div><div class="wrap">
<header><a href="${SITE}/" class="logo">KART<b>İST</b></a><a href="${SITE}/" class="back-home">← Ana Sayfa</a></header>
<div class="crumb"><a href="${SITE}/">Ana Sayfa</a> › Pokemon › ${esc(pname)}</div>
<h1>${esc(pname)} Kartları</h1>
<div class="meta">${cardSlugs.length} kart · tüm setler · güncel fiyatlar</div>
<div class="card"><h2>🃏 Tüm ${esc(pname)} Kartları</h2><div class="clist">${tiles}</div></div>
<div class="card co"><h2>🎴 Daha Fazlası</h2>
  <p style="color:#c7cce3;margin-bottom:14px">${esc(pname)} çekmek için sanal paket aç veya diğer Pokemon kartlarına bak.</p>
  <div class="cta-row"><a class="cta" href="${SITE}/#paket-ac">🎴 Paket Aç</a><a class="cta alt" href="${SITE}/#fiyatlar">💰 Kart Fiyatları</a></div>
</div>
<div class="foot"><a href="${SITE}/">Kartist</a> — Türkiye'nin Pokemon TCG araç merkezi · 17.700+ kart</div>
</div><!-- Cloudflare Web Analytics --><script defer src='https://static.cloudflareinsights.com/beacon.min.js' data-cf-beacon='{"token": "cc61c614f4de468580012bd1f4c750c9"}'></script><!-- End Cloudflare Web Analytics --></body></html>`;
}


